// npm install bcryptjs  (atau bcrypt untuk native binding)
const bcrypt = require('bcryptjs');

// ==========================================
// HASHING PASSWORD
// ==========================================
const SALT_ROUNDS = 12;

async function hashPassword(passwordPlain) {
  const hash = await bcrypt.hash(passwordPlain, SALT_ROUNDS);
  return hash;
}

// ==========================================
// VERIFIKASI PASSWORD
// ==========================================
async function verifyPassword(passwordPlain, passwordHash) {
  const isMatch = await bcrypt.compare(passwordPlain, passwordHash);
  return isMatch;
}

