// INTEGRASI DENGAN MODEL USER (Mongoose)
// ==========================================
const mongoose = require('mongoose');
const { Schema, model } = mongoose;

const userSchema = new Schema({
  email:    { type: String, required: true, unique: true, lowercase: true },
  password: { type: String, required: true, minlength: 6 },
  nama:     { type: String, required: true }
}, { timestamps: true });

// Pre-save hook: hash password SEBELUM disimpan
userSchema.pre('save', async function(next) {
  if (!this.isModified('password')) return next();
  this.password = await bcrypt.hash(this.password, SALT_ROUNDS);
  next();
});

// Method instance untuk verifikasi password
userSchema.methods.comparePassword = async function(candidatePassword) {
  return await bcrypt.compare(candidatePassword, this.password);
};

const User = model('User', userSchema);

module.exports = { User, hashPassword, verifyPassword };

// npm install jsonwebtoken dotenv
const jwt = require('jsonwebtoken');
require('dotenv').config();

const JWT_SECRET = process.env.JWT_SECRET;
const JWT_EXPIRES_IN = '15m';
const REFRESH_EXPIRES_IN = '7d';

function generateAccessToken(user) {
  const payload = {
    sub:   user._id.toString(),
    email: user.email,
    role:  user.role || 'user'
  };
  return jwt.sign(payload, JWT_SECRET, {
    expiresIn: JWT_EXPIRES_IN,
    issuer:    'web-belajar-api'
  });
}

function generateRefreshToken(user) {
  return jwt.sign(
    { sub: user._id.toString() },
    JWT_SECRET,
    { expiresIn: REFRESH_EXPIRES_IN }
  );
}

function verifyToken(token) {
  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    return { valid: true, decoded };
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return { valid: false, error: 'Token sudah expired', expiredAt: err.expiredAt };
    }
    if (err.name === 'JsonWebTokenError') {
      return { valid: false, error: 'Token tidak valid' };
    }
    return { valid: false, error: err.message };
  }
}

module.exports = { generateAccessToken, generateRefreshToken, verifyToken };

