const { User } = require('../models/User');
const { generateAccessToken, generateRefreshToken } = require('../utils/jwt');

async function register(req, res, next) {
  try {
    const { email, password, nama } = req.body;
    if (!email || !password || !nama) {
      return res.status(400).json({ message: 'Semua field wajib diisi' });
    }
    const existingUser = await User.findOne({ email: email.toLowerCase() });
    if (existingUser) {
      return res.status(409).json({ message: 'Email sudah terdaftar' });
    }
    const user = await User.create({ email, password, nama });
    const accessToken  = generateAccessToken(user);
    const refreshToken = generateRefreshToken(user);
    user.refreshTokens = user.refreshTokens || [];
    user.refreshTokens.push({ token: refreshToken, createdAt: new Date() });
    await user.save();
    res.status(201).json({
      message: 'Registrasi berhasil',
      data: {
        user: { id: user._id, email: user.email, nama: user.nama, role: user.role },
        accessToken,
        refreshToken
      }
    });
  } catch (err) {
    next(err);
  }
}

async function login(req, res, next) {
  try {
    const { email, password } = req.body;
    const user = await User.findOne({ email: email.toLowerCase() }).select('+password');
    if (!user || !(await user.comparePassword(password))) {
      return res.status(401).json({ message: 'Email atau password salah' });
    }
    if (!user.isActive) {
      return res.status(403).json({ message: 'Akun dinonaktifkan' });
    }
    const accessToken  = generateAccessToken(user);
    const refreshToken = generateRefreshToken(user);
    user.refreshTokens = user.refreshTokens || [];
    user.refreshTokens.push({ token: refreshToken, createdAt: new Date() });
    if (user.refreshTokens.length > 5) {
      user.refreshTokens = user.refreshTokens.slice(-5);
    }
    await user.save();
    res.status(200).json({
      message: 'Login berhasil',
      data: {
        user: { id: user._id, email: user.email, nama: user.nama, role: user.role },
        accessToken,
        refreshToken
      }
    });
  } catch (err) {
    next(err);
  }
}

async function refresh(req, res, next) {
  try {
    const { refreshToken } = req.body;
    if (!refreshToken) {
      return res.status(401).json({ message: 'Refresh token diperlukan' });
    }
    const { valid, decoded, error } = verifyToken(refreshToken);
    if (!valid) {
      return res.status(403).json({ message: error });
    }
    const user = await User.findById(decoded.sub);
    const tokenExists = user?.refreshTokens?.some(t => t.token === refreshToken);
    if (!tokenExists) {
      return res.status(403).json({ message: 'Refresh token tidak valid' });
    }
    const newAccessToken = generateAccessToken(user);
    res.json({ accessToken: newAccessToken });
  } catch (err) {
    next(err);
  }
}

async function logout(req, res, next) {
  try {
    const { refreshToken } = req.body;
    const userId = req.user.sub;
    await User.findByIdAndUpdate(userId, {
      $pull: { refreshTokens: { token: refreshToken } }
    });
    res.json({ message: 'Logout berhasil' });
  } catch (err) {
    next(err);
  }
}

module.exports = { register, login, refresh, logout };

