const { verifyToken } = require('../utils/jwt');
const { User } = require('../models/User');

async function authenticate(req, res, next) {
  try {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return res.status(401).json({ message: 'Akses ditolak. Token tidak ditemukan.' });
    }
    const token = authHeader.split(' ')[1];
    const { valid, decoded, error } = verifyToken(token);
    if (!valid) {
      return res.status(401).json({ message: `Token tidak valid: ${error}` });
    }
    const user = await User.findById(decoded.sub).select('-password -refreshTokens');
    if (!user || !user.isActive) {
      return res.status(401).json({ message: 'User tidak ditemukan atau dinonaktifkan' });
    }
    req.user = {
      id:    decoded.sub,
      email: decoded.email,
      role:  decoded.role,
      ...user.toObject()
    };
    next();
  } catch (err) {
    next(err);
  }
}

function authorize(...allowedRoles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ message: 'Autentikasi diperlukan' });
    }
    if (!allowedRoles.includes(req.user.role)) {
      return res.status(403).json({
        message: `Akses ditolak. Role '${req.user.role}' tidak memiliki izin.`
      });
    }
    next();
  };
}

async function optionalAuth(req, res, next) {
  try {
    const authHeader = req.headers.authorization;
    if (authHeader && authHeader.startsWith('Bearer ')) {
      const token = authHeader.split(' ')[1];
      const { valid, decoded } = verifyToken(token);
      if (valid) req.user = decoded;
    }
    next();
  } catch (err) {
    next();
  }
}

module.exports = { authenticate, authorize, optionalAuth };

