// controllers/authController.js (Refresh dengan Rotasi)
// ==========================================
async function refresh(req, res, next) {
  try {
    const { refreshToken } = req.body;
    if (!refreshToken) {
      return res.status(401).json({ message: 'Refresh token diperlukan' });
    }
    const { valid, decoded, error } = verifyToken(refreshToken);
    if (!valid) {
      return res.status(403).json({ message: 'Refresh token tidak valid' });
    }
    const user = await User.findById(decoded.sub);
    if (!user) {
      return res.status(403).json({ message: 'User tidak ditemukan' });
    }
    const tokenIndex = user.refreshTokens.findIndex(t => t.token === refreshToken);
    if (tokenIndex === -1) {
      user.refreshTokens = [];
      await user.save();
      return res.status(403).json({
        message: 'Refresh token tidak valid. Silakan login ulang.'
      });
    }
    const newAccessToken  = generateAccessToken(user);
    const newRefreshToken = generateRefreshToken(user);
    user.refreshTokens[tokenIndex] = {
      token: newRefreshToken,
      createdAt: new Date()
    };
    await user.save();
    res.json({
      accessToken:  newAccessToken,
      refreshToken: newRefreshToken
    });
  } catch (err) {
    next(err);
  }
}

async function logoutAllDevices(req, res, next) {
  try {
    const userId = req.user.id;
    await User.findByIdAndUpdate(userId, { refreshTokens: [] });
    res.json({ message: 'Berhasil logout dari semua perangkat' });
  } catch (err) {
    next(err);
  }
}

module.exports = { refresh, logoutAllDevices };

