const Joi = require('joi');

const registerSchema = Joi.object({
  nama: Joi.string()
    .min(3).max(100).trim().required()
    .messages({
      'string.min': 'Nama minimal 3 karakter',
      'string.max': 'Nama maksimal 100 karakter',
      'any.required': 'Nama wajib diisi'
    }),
  email: Joi.string()
    .email({ minDomainSegments: 2, tlds: { allow: ['com', 'net', 'id', 'org'] } })
    .lowercase().trim().required(),
  password: Joi.string()
    .min(8).max(128)
    .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]+$/)
    .required()
    .messages({
      'string.pattern.base': 'Password harus mengandung huruf besar, huruf kecil, angka, dan simbol'
    }),
  konfirmasiPassword: Joi.string()
    .valid(Joi.ref('password')).required()
    .messages({ 'any.only': 'Konfirmasi password tidak cocok' }),
  umur: Joi.number().integer().min(17).max(60).optional(),
  role: Joi.string().valid('user', 'admin', 'dosen').default('user')
}).with('password', 'konfirmasiPassword');

function validate(schema) {
  return (req, res, next) => {
    const { error, value } = schema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true
    });
    if (error) {
      const errors = error.details.map(d => ({
        field: d.path[0],
        message: d.message
      }));
      return res.status(400).json({ message: 'Validasi gagal', errors });
    }
    req.body = value;
    next();
  };
}

