// OPSI 2: express-validator
// ==========================================
const { body, validationResult } = require('express-validator');

const registerValidators = [
  body('nama').trim().notEmpty().withMessage('Nama wajib diisi')
    .isLength({ min: 3, max: 100 }).withMessage('Nama harus 3-100 karakter'),
  body('email').trim().isEmail().withMessage('Format email tidak valid')
    .normalizeEmail().toLowerCase(),
  body('password').isLength({ min: 8 }).withMessage('Password minimal 8 karakter')
    .matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/)
    .withMessage('Password harus mengandung huruf besar, huruf kecil, dan angka'),
  body('konfirmasiPassword').custom((value, { req }) => {
    if (value !== req.body.password) {
      throw new Error('Konfirmasi password tidak cocok');
    }
    return true;
  })
];

function handleValidationErrors(req, res, next) {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({
      message: 'Validasi gagal',
      errors: errors.array().map(e => ({ field: e.path, message: e.msg }))
    });
  }
  next();
}

module.exports = { validate, registerSchema, registerValidators, handleValidationErrors };

